<?php
namespace App\Actions;
use App\Models\{InventoryMovement,Material,MaterialWriteOff,Project};use App\Services\InventoryService;use Illuminate\Support\Facades\DB;
class CreateMaterialWriteOffAction{public function __construct(private InventoryService $inventory){} public function execute(array $data): MaterialWriteOff{return DB::transaction(function() use($data){$project=Project::findOrFail($data['project_id']);$material=Material::findOrFail($data['material_id']);$this->inventory->assertCanWriteOff($project,$material,(float)$data['quantity']);$unit=$this->inventory->getAverageUnitCost($project,$material);$total=round((float)$data['quantity']*$unit,2);$tagIds=$data['tag_ids']??[];unset($data['tag_ids']);$wo=MaterialWriteOff::create($data+['unit_price'=>$unit,'total_amount'=>$total]);InventoryMovement::create(['project_id'=>$wo->project_id,'material_id'=>$wo->material_id,'date'=>$wo->date,'type'=>'out','quantity'=>$wo->quantity,'unit_price'=>$unit,'amount'=>$total,'source_type'=>$wo::class,'source_id'=>$wo->id,'comment'=>$wo->comment]);$wo->tags()->sync($tagIds);return $wo->load('tags');});}}
